input.content:
"use client"

import { useEffect, useState, useCallback } from "react"
import { useRouter } from "next/navigation"
import { Command } from "cmdk"
import {
    IconFileText,
    IconBrandGithub,
    IconRocket,
    IconHome,
    IconSearch,
    IconTerminal,
} from "@tabler/icons-react"
import type { PostWithMeta } from "@/lib/blog"
import type { Project } from "@/lib/projects"
import type { MiniApp } from "@/lib/mini-apps"

interface CommandMenuProps {
    posts: PostWithMeta[]
    projects: Project[]
    miniApps: MiniApp[]
}

export function CommandMenu({ posts, projects, miniApps }: CommandMenuProps) {
    const [open, setOpen] = useState(false)
    const router = useRouter()

    useEffect(() => {
        const down = (e: KeyboardEvent) => {
            if (e.key === "k" && (e.metaKey || e.ctrlKey)) {
                e.preventDefault()
                setOpen((open) => !open)
            }
        }
        document.addEventListener("keydown", down)
        return () => document.removeEventListener("keydown", down)
    }, [])

    const runAction = useCallback(
        (action: () => void) => {
            setOpen(false)
            action()
        },
        []
    )

    return (
        <Command.Dialog
            open={open}
            onOpenChange={setOpen}
            label="Search"
            className="fixed inset-0 z-[100] bg-background/80 backdrop-blur-sm"
            overlayClassName="fixed inset-0 bg-background/80 backdrop-blur-sm"
            contentClassName="fixed left-1/2 top-[20%] z-[101] w-full max-w-lg -translate-x-1/2 rounded-xl border border-border/50 bg-background shadow-2xl"
        >
            <Command.Input
                placeholder="Search blog, projects, pages..."
                className="flex h-12 w-full rounded-t-xl border-b border-border/50 bg-transparent px-4 text-sm outline-none placeholder:text-muted-foreground"
            />
            <Command.List className="max-h-[300px] overflow-y-auto p-2">
                <Command.Empty className="py-6 text-center text-sm text-muted-foreground">
                    No results found.
                </Command.Empty>

                <Command.Group heading="Pages" className="mb-2">
                    <CommandItem
                        value="home"
                        onSelect={() => runAction(() => router.push("/"))}
                    >
                        <IconHome className="h-4 w-4 shrink-0 text-muted-foreground" />
                        <span>Home</span>
                    </CommandItem>
                    <CommandItem
                        value="blog"
                        onSelect={() => runAction(() => router.push("/blog"))}
                    >
                        <IconFileText className="h-4 w-4 shrink-0 text-muted-foreground" />
                        <span>Blog</span>
                    </CommandItem>
                    <CommandItem
                        value="mini apps"
                        onSelect={() => runAction(() => router.push("/mini-apps"))}
                    >
                        <IconTerminal className="h-4 w-4 shrink-0 text-muted-foreground" />
                        <span>Mini Apps</span>
                    </CommandItem>
                </Command.Group>

                <Command.Separator className="my-1 h-px bg-border/50" />

                <Command.Group heading="Blog Posts" className="mb-2">
                    {posts.map((post) => (
                        <CommandItem
                            key={post.slug}
                            value={`blog-${post.slug}`}
                            keywords={post.frontmatter.tags}
                            onSelect={() =>
                                runAction(() => router.push(`/blog/${post.slug}`))
                            }
                        >
                            <IconFileText className="h-4 w-4 shrink-0 text-muted-foreground" />
                            <div className="flex flex-col">
                                <span>{post.frontmatter.title}</span>
                                {post.frontmatter.description && (
                                    <span className="text-xs text-muted-foreground line-clamp-1">
                                        {post.frontmatter.description}
                                    </span>
                                )}
                            </div>
                        </CommandItem>
                    ))}
                </Command.Group>

                <Command.Separator className="my-1 h-px bg-border/50" />

                <Command.Group heading="Projects" className="mb-2">
                    {projects.map((project) => (
                        <CommandItem
                            key={project.title}
                            value={`project-${project.title}`}
                            onSelect={() => runAction(() => window.open(project.href, "_blank"))}
                        >
                            <IconBrandGithub className="h-4 w-4 shrink-0 text-muted-foreground" />
                            <div className="flex flex-col">
                                <span>{project.title}</span>
                                <span className="text-xs text-muted-foreground line-clamp-1">
                                    {project.description}
                                </span>
                            </div>
                        </CommandItem>
                    ))}
                </Command.Group>

                <Command.Separator className="my-1 h-px bg-border/50" />

                <Command.Group heading="Mini Apps" className="mb-2">
                    {miniApps.map((app) => (
                        <CommandItem
                            key={app.title}
                            value={`mini-${app.title}`}
                            onSelect={() =>
                                runAction(() => {
                                    const url = app.live || app.code
                                    if (url) window.open(url, "_blank")
                                })
                            }
                        >
                            <IconRocket className="h-4 w-4 shrink-0 text-muted-foreground" />
                            <div className="flex flex-col">
                                <span>{app.title}</span>
                                <span className="text-xs text-muted-foreground line-clamp-1">
                                    {app.description}
                                </span>
                            </div>
                        </CommandItem>
                    ))}
                </Command.Group>
            </Command.List>
        </Command.Dialog>
    )
}

function CommandItem({
    children,
    ...props
}: {
    children: React.ReactNode
    value: string
    onSelect?: (value: string) => void
    keywords?: string[]
}) {
    return (
        <Command.Item
            className="flex items-center gap-3 rounded-md px-3 py-2 text-sm cursor-pointer data-[selected=true]:bg-accent data-[selected=true]:text-foreground"
            {...props}
        >
            {children}
        </Command.Item>
    )
}

