@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
}

/* Smooth theme transitions */
html {
  transition: color-scheme 0.3s ease-in-out;
}

body,
.theme-transition {
  transition:
    background-color 0.1s ease-in-out,
    border-color 0.1s ease-in-out,
    color 0.1s ease-in-out,
    fill 0.1s ease-in-out,
    stroke 0.1s ease-in-out,
    box-shadow 0.1s ease-in-out;
}

/* Disable transitions during page load to prevent initial animation */
.disable-transitions * {
  transition: none !important;
}

/* View Transition Wave Effect */
::view-transition-old(root),
::view-transition-new(root) {
  animation: none;
  mix-blend-mode: normal;
}

::view-transition-old(root) {
  /* Ensure the outgoing view (old theme) is beneath */
  z-index: 0;
}

::view-transition-new(root) {
  /* Ensure the incoming view (new theme) is always on top */
  z-index: 1;
}

@keyframes reveal {
  from {
    /* Use CSS variables for the origin, defaulting to center if not set */
    clip-path: circle(0% at var(--x, 50%) var(--y, 50%));
    opacity: 0.7;
  }
  to {
    /* Use CSS variables for the origin, defaulting to center if not set */
    clip-path: circle(150% at var(--x, 50%) var(--y, 50%));
    opacity: 1;
  }
}

::view-transition-new(root) {
  /* Apply the reveal animation */
  animation: reveal 0.9s ease-in-out forwards;
}

/* Override prose-ui container bg to match page */
.prose-ui {
   /* Ensure container blends with page background in all themes */
   background-color: var(--background) !important;
   background: var(--background) !important;
}

/* Spoiler styling */
span.spoiler {
   cursor: pointer;
   transition: filter 0.3s ease-in-out;
   filter: blur(4px);
   user-select: text;
   display: inline-block;
}

span.spoiler:hover {
   filter: blur(0);
}

span.spoiler:focus {
   filter: blur(0);
   outline: 2px solid var(--ring);
   outline-offset: 2px;
}

/* For touch devices, use click to toggle */
span.spoiler[data-revealed="true"] {
    filter: blur(0);
}

/* Blog post image styling */
.prose-ui img {
    display: block;
    width: 150%;
    height: auto;
    max-width: none;
    border-radius: 8px;
    margin: 2.5rem auto 2.5rem -25%;
    box-shadow: 0 10px 25px rgba(0, 0, 0, 0.15);
}

@media (max-width: 768px) {
    .prose-ui img {
        width: 100%;
        margin: 1.5rem auto;
    }
}

