"use client"

import { useEffect, useState, useCallback } from "react"
import { useRouter } from "next/navigation"
import { Command } from "cmdk"
import {
    IconFileText,
    IconBrandGithub,
    IconRocket,
    IconHome,
    IconSearch,
    IconTerminal,
    IconPointer,
} from "@tabler/icons-react"
import type { PostWithMeta } from "@/lib/blog"
import type { Project } from "@/lib/projects"
import type { MiniApp } from "@/lib/mini-apps"

interface CommandMenuProps {
    posts: PostWithMeta[]
    projects: Project[]
    miniApps: MiniApp[]
}

export function CommandMenu({ posts, projects, miniApps }: CommandMenuProps) {
    const [open, setOpen] = useState(false)
    const router = useRouter()

    useEffect(() => {
        const down = (e: KeyboardEvent) => {
            if (e.key === "k" && (e.metaKey || e.ctrlKey)) {
                e.preventDefault()
                setOpen((open) => !open)
            }
        }
        document.addEventListener("keydown", down)
        return () => document.removeEventListener("keydown", down)
    }, [])

    const runAction = useCallback(
        (action: () => void) => {
            setOpen(false)
            action()
        },
        []
    )

    return (
        <Command.Dialog
            open={open}
            onOpenChange={setOpen}
            label="Search"
            className="fixed inset-0 z-[100]"
            overlayClassName="fixed inset-0 bg-black/40 backdrop-blur-sm data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0"
            contentClassName="fixed left-1/2 top-[20%] z-[101] w-full max-w-md -translate-x-1/2 overflow-hidden rounded-2xl border border-border/40 bg-background shadow-2xl data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 data-[state=closed]:slide-out-to-left-1/2 data-[state=closed]:slide-out-to-top-[48%] data-[state=open]:slide-in-from-left-1/2 data-[state=open]:slide-in-from-top-[48%]"
        >
            <div className="flex items-center border-b border-border/40 px-4">
                <IconSearch className="h-4 w-4 shrink-0 text-muted-foreground" />
                <Command.Input
                    placeholder="Search..."
                    className="flex h-11 w-full bg-transparent pl-3 text-sm outline-none placeholder:text-muted-foreground"
                />
                <kbd className="pointer-events-none hidden h-5 select-none items-center gap-1 rounded border border-border/40 bg-muted px-1.5 font-mono text-[10px] font-medium text-muted-foreground sm:flex">
                    esc
                </kbd>
            </div>
            <Command.List className="max-h-[320px] overflow-y-auto overflow-x-hidden p-1.5">
                <Command.Empty className="flex flex-col items-center justify-center gap-2 py-8 text-sm text-muted-foreground">
                    <IconSearch className="h-5 w-5 text-muted-foreground/50" />
                    <span>No results found.</span>
                </Command.Empty>

                <Command.Group heading="Pages" className="mb-1">
                    <CommandItem
                        value="home"
                        onSelect={() => runAction(() => router.push("/"))}
                    >
                        <IconHome className="h-4 w-4 shrink-0 text-muted-foreground" />
                        <span>Home</span>
                    </CommandItem>
                    <CommandItem
                        value="blog"
                        onSelect={() => runAction(() => router.push("/blog"))}
                    >
                        <IconFileText className="h-4 w-4 shrink-0 text-muted-foreground" />
                        <span>Blog</span>
                    </CommandItem>
                    <CommandItem
                        value="mini apps"
                        onSelect={() => runAction(() => router.push("/mini-apps"))}
                    >
                        <IconTerminal className="h-4 w-4 shrink-0 text-muted-foreground" />
                        <span>Mini Apps</span>
                    </CommandItem>
                </Command.Group>

                <Command.Separator className="my-1 h-px bg-border/30" />

                <Command.Group heading="Blog Posts" className="mb-1">
                    {posts.map((post) => (
                        <CommandItem
                            key={post.slug}
                            value={`blog-${post.slug}`}
                            keywords={post.frontmatter.tags}
                            onSelect={() =>
                                runAction(() => router.push(`/blog/${post.slug}`))
                            }
                        >
                            <IconFileText className="h-4 w-4 shrink-0 text-muted-foreground" />
                            <div className="flex min-w-0 flex-col">
                                <span className="truncate">{post.frontmatter.title}</span>
                                {post.frontmatter.description && (
                                    <span className="truncate text-xs text-muted-foreground">
                                        {post.frontmatter.description}
                                    </span>
                                )}
                            </div>
                        </CommandItem>
                    ))}
                </Command.Group>

                <Command.Separator className="my-1 h-px bg-border/30" />

                <Command.Group heading="Projects" className="mb-1">
                    {projects.map((project) => (
                        <CommandItem
                            key={project.title}
                            value={`project-${project.title}`}
                            onSelect={() => runAction(() => window.open(project.href, "_blank"))}
                        >
                            <IconBrandGithub className="h-4 w-4 shrink-0 text-muted-foreground" />
                            <div className="flex min-w-0 flex-col">
                                <span className="truncate">{project.title}</span>
                                <span className="truncate text-xs text-muted-foreground">
                                    {project.description}
                                </span>
                            </div>
                        </CommandItem>
                    ))}
                </Command.Group>

                <Command.Separator className="my-1 h-px bg-border/30" />

                <Command.Group heading="Mini Apps" className="mb-1">
                    {miniApps.map((app) => (
                        <CommandItem
                            key={app.title}
                            value={`mini-${app.title}`}
                            onSelect={() =>
                                runAction(() => {
                                    const url = app.live || app.code
                                    if (url) window.open(url, "_blank")
                                })
                            }
                        >
                            <IconRocket className="h-4 w-4 shrink-0 text-muted-foreground" />
                            <div className="flex min-w-0 flex-col">
                                <span className="truncate">{app.title}</span>
                                <span className="truncate text-xs text-muted-foreground">
                                    {app.description}
                                </span>
                            </div>
                        </CommandItem>
                    ))}
                </Command.Group>
            </Command.List>
            <div className="flex items-center gap-4 border-t border-border/40 px-4 py-2.5 text-[11px] text-muted-foreground">
                <div className="flex items-center gap-1.5">
                    <kbd className="rounded border border-border/40 bg-muted px-1 py-0.5 font-mono text-[10px]">↑</kbd>
                    <kbd className="rounded border border-border/40 bg-muted px-1 py-0.5 font-mono text-[10px]">↓</kbd>
                    <span>navigate</span>
                </div>
                <div className="flex items-center gap-1.5">
                    <kbd className="rounded border border-border/40 bg-muted px-1 py-0.5 font-mono text-[10px]">↵</kbd>
                    <span>open</span>
                </div>
                <div className="flex items-center gap-1.5">
                    <kbd className="rounded border border-border/40 bg-muted px-1 py-0.5 font-mono text-[10px]">esc</kbd>
                    <span>close</span>
                </div>
            </div>
        </Command.Dialog>
    )
}

function CommandItem({
    children,
    ...props
}: {
    children: React.ReactNode
    value: string
    onSelect?: (value: string) => void
    keywords?: string[]
}) {
    return (
        <Command.Item
            className="flex items-center gap-3 rounded-lg px-3 py-2 text-sm cursor-pointer outline-none data-[selected=true]:bg-accent/15 data-[selected=true]:text-foreground transition-colors"
            {...props}
        >
            {children}
        </Command.Item>
    )
}

