                                    {app.description}
                                </span>
                            </div>
                        </CommandItem>
                    ))}
                </Command.Group>
            </Command.List>
        </Command.Dialog>
    )
}

function CommandItem({
    children,
    ...props
}: {
    children: React.ReactNode
    value: string
    onSelect?: (value: string) => void
    keywords?: string[]
}) {
    return (
        <Command.Item
            className="cmdk-item"
            {...props}
        >
            {children}
        </Command.Item>
    )
}

