/* Cmdk command menu */
[cmdk-overlay] {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.4);
  backdrop-filter: blur(4px);
  z-index: 100;
}

[cmdk-dialog] {
  position: fixed;
  left: 50%;
  top: 20%;
  z-index: 101;
  width: 100%;
  max-width: 28rem;
  transform: translateX(-50%);
  overflow: hidden;
  border-radius: 1rem;
  border: 1px solid var(--border);
  background: var(--background);
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
}

[cmdk-input] {
  display: flex;
  height: 3rem;
  width: 100%;
  border-bottom: 1px solid var(--border);
  background: transparent;
  padding: 0 1rem;
  font-size: 0.875rem;
  outline: none;
}

[cmdk-input]::placeholder {
  color: var(--muted-foreground);
}

[cmdk-list] {
  max-height: 320px;
  overflow-y: auto;
  overflow-x: hidden;
  padding: 0.375rem;
}

[cmdk-empty] {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  padding: 2rem 0;
  font-size: 0.875rem;
  color: var(--muted-foreground);
}

[cmdk-group] {
  margin-bottom: 0.25rem;
}

[cmdk-group-heading] {
  padding: 0.5rem 0.75rem 0.25rem;
  font-size: 0.7rem;
  font-weight: 500;
  letter-spacing: 0.05em;
  color: var(--muted-foreground);
}

[cmdk-item] {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  border-radius: 0.5rem;
  padding: 0.5rem 0.75rem;
  font-size: 0.875rem;
  cursor: pointer;
  transition: background 0.1s ease;
}

[cmdk-item][data-selected="true"] {
  background: oklch(0.25 0.02 150 / 0.3);
  color: var(--foreground);
}

[cmdk-item]:active {
  opacity: 0.7;
}

[cmdk-separator] {
  height: 1px;
  margin: 0.25rem 0;
  background: var(--border);
  opacity: 0.3;
}

[cmdk-root] {
  width: 100%;
}

/* Blog post image styling */

